import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        if (args.length < 1) {
            System.out.println("Please provide a file path as input.");
            return;
        }

        String userInput = args[0];
        Path basePath = Paths.get("/var/data");
        Path resolvedPath = basePath.resolve(Paths.get(userInput)).normalize();

        if (!resolvedPath.startsWith(basePath)) {
            System.out.println("Invalid file path.");
            return;
        }

        try (BufferedReader br = new BufferedReader(new FileReader(resolvedPath.toFile()))) {
            String line;
            while ((line = br.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Path Traversal
